2: import { NextResponse, type NextRequest } from "next/server";
3: 
4: /**
5:  * Refreshes the Supabase auth session and writes updated tokens
6:  * back to the response cookies. This must run in the proxy (middleware)
7:  * so that expired sessions are refreshed before any page renders.
8:  */
9: export async function updateSession(request: NextRequest) {
10:   let supabaseResponse = NextResponse.next({
11:     request,
12:   });
13: 
14:   const supabase = createServerClient(
15:     process.env.NEXT_PUBLIC_SUPABASE_URL!,
16:     process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
17:     {
18:       cookies: {
19:         getAll() {
20:           return request.cookies.getAll();
21:         },
22:         setAll(cookiesToSet, headers) {
23:           // Forward updated cookies to the request so downstream
24:           // Server Components can read the refreshed session.
25:           cookiesToSet.forEach(({ name, value }) =>
26:             request.cookies.set(name, value)
27:           );
28: 
29:           supabaseResponse = NextResponse.next({
30:             request,
31:           });
32: 
33:           // Write cookies to the response so the browser stores them.
34:           cookiesToSet.forEach(({ name, value, options }) =>
35:             supabaseResponse.cookies.set(name, value, options)
36:           );
37: 
38:           // Apply cache-busting headers to prevent CDNs from
39:           // caching responses that set auth cookies.
40:           if (headers) {
41:             Object.entries(headers).forEach(([key, value]) =>
42:               supabaseResponse.headers.set(key, value)
43:             );
44:           }
45:         },
46:       },
47:     }
48:   );
49: 
50:   // IMPORTANT: Call getUser() to trigger token refresh.
51:   // Do NOT use getSession() — it reads from cookies without
52:   // validating the token against the Supabase Auth server.
53:   const {
54:     data: { user },
55:   } = await supabase.auth.getUser();
56: 
57:   // Protect /dashboard — redirect unauthenticated users to /login
58:   if (
59:     !user &&
60:     request.nextUrl.pathname.startsWith("/dashboard")
61:   ) {
62:     const url = request.nextUrl.clone();
63:     url.pathname = "/login";
64:     return NextResponse.redirect(url);
65:   }
66: 
67:   return supabaseResponse;
68: }
