{"File":"/home/ketan/eagerminds-task/.gemini/transcript","LineNumber":4045,"LineContent":"      \"content\": \"Created At: 2026-06-06T03:11:17Z\\nCompleted At: 2026-06-06T03:11:17Z\\nFile Path: `file:///home/ketan/eagerminds-task/src/app/api/welcome-email/route.ts`\\nTotal Lines: 122\\nTotal Bytes: 4988\\nShowing lines 1 to 122\\nThe following code has been modified to include a line number before every line, in the format: \u003cline_number\u003e: \u003coriginal_line\u003e. Please note that any changes targeting the original code should remove the line number, colon, and leading space.\\n1: import { NextResponse } from \\\"next/server\\\";\\n2: \\n3: /**\\n4:  * POST /api/welcome-email\\n5:  *\\n6:  * Sends a welcome email to a newly registered user via the Resend API.\\n7:  * Called internally after a successful Supabase signup.\\n8:  */\\n9: export async function POST(request: Request) {\\n10:   try {\\n11:     const { email, name } = await request.json();\\n12: \\n13:     if (!email) {\\n14:       return NextResponse.json(\\n15:         { error: \\\"Email is required\\\" },\\n16:         { status: 400 }\\n17:       );\\n18:     }\\n19: \\n20:     const resendApiKey = process.env.RESEND_API_KEY;\\n21:     if (!resendApiKey) {\\n22:       console.error(\\\"RESEND_API_KEY is not set\\\");\\n23:       return NextResponse.json(\\n24:         { error: \\\"Email service not configured\\\" },\\n25:         { status: 500 }\\n26:       );\\n27:     }\\n28: \\n29:     const displayName = name || email.split(\\\"@\\\")[0];\\n30: \\n31:     const res = await fetch(\\\"https://api.resend.com/emails\\\", {\\n32:       method: \\\"POST\\\",\\n33:       headers: {\\n34:         \\\"Content-Type\\\": \\\"application/json\\\",\\n35:         Authorization: `Bearer ${resendApiKey}`,\\n36:       },\\n37:       body: JSON.stringify({\\n38:         from: \\\"Bookmarks \u003conboarding@resend.dev\u003e\\\",\\n39:         to: [email],\\n40:         subject: \\\"Welcome to Bookmarks \\ud83d\\udd16\\\",\\n41:         html: `\\n42:           \u003c!DOCTYPE html\u003e\\n43:           \u003chtml\u003e\\n44:             \u003chead\u003e\\n45:               \u003cmeta charset=\\\"utf-8\\\" /\u003e\\n46:               \u003cmeta name=\\\"viewport\\\" content=\\\"width=device-width, initial-scale=1\\\" /\u003e\\n47:             \u003c/head\u003e\\n48:             \u003cbody style=\\\"margin:0;padding:0;background-color:#0f0f14;font-family:'Segoe \\n\u003ctruncated 1928 bytes\u003e\\nnv.NEXT_PUBLIC_SUPABASE_URL).origin : \\\"#\\\"}\\\"\\n76:                                    style=\\\"display:inline-block;padding:14px 32px;background:linear-gradient(135deg,#8b5cf6,#6d28d9);color:#ffffff;font-size:15px;font-weight:600;text-decoration:none;border-radius:10px;letter-spacing:0.3px;\\\"\u003e\\n77:                                   Go to Dashboard \\u2192\\n78:                                 \u003c/a\u003e\\n79:                               \u003c/td\u003e\\n80:                             \u003c/tr\u003e\\n81:                           \u003c/table\u003e\\n82:                         \u003c/td\u003e\\n83:                       \u003c/tr\u003e\\n84:                       \u003c!-- Footer --\u003e\\n85:                       \u003ctr\u003e\\n86:                         \u003ctd style=\\\"padding:24px 40px;border-top:1px solid rgba(255,255,255,0.06);text-align:center;\\\"\u003e\\n87:                           \u003cp style=\\\"margin:0;font-size:13px;color:#64648b;\\\"\u003e\\n88:                             You're receiving this because you signed up for Bookmarks.\u003cbr/\u003e\\n89:                             If you didn't create this account, you can safely ignore this email.\\n90:                           \u003c/p\u003e\\n91:                         \u003c/td\u003e\\n92:                       \u003c/tr\u003e\\n93:                     \u003c/table\u003e\\n94:                   \u003c/td\u003e\\n95:                 \u003c/tr\u003e\\n96:               \u003c/table\u003e\\n97:             \u003c/body\u003e\\n98:           \u003c/html\u003e\\n99:         `,\\n100:       }),\\n101:     });\\n102: \\n103:     if (!res.ok) {\\n104:       const errorData = await res.json();\\n105:       console.error(\\\"Resend API error:\\\", errorData);\\n106:       return NextResponse.json(\\n107:         { error: \\\"Failed to send welcome email\\\" },\\n108:         { status: 500 }\\n109:       );\\n110:     }\\n111: \\n112:     const data = await res.json();\\n113:     return NextResponse.json({ success: true, id: data.id });\\n114:   } catch (error) {\\n115:     console.error(\\\"Welcome email error:\\\", error);\\n116:     return NextResponse.json(\\n117:       { error: \\\"Internal server error\\\" },\\n118:       { status: 500 }\\n119:     );\\n120:   }\\n121: }\\n122: \\nThe above content shows the entire, complete file contents of the requested file.\\n\""}
